"use strict";(self.webpackChunkblog=self.webpackChunkblog||[]).push([[9950],{2018:(e,n,s)=>{s.r(n),s.d(n,{data:()=>a});const a={key:"v-be355246",path:"/leetcode/dayOne/1723.%20%E5%AE%8C%E6%88%90%E6%89%80%E6%9C%89%E5%B7%A5%E4%BD%9C%E7%9A%84%E6%9C%80%E7%9F%AD%E6%97%B6%E9%97%B4.html",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:2,title:"完成所有工作的最短时间",slug:"完成所有工作的最短时间",children:[{level:3,title:"示例 1：",slug:"示例-1",children:[]},{level:3,title:"示例 2：",slug:"示例-2",children:[]}]}],filePathRelative:"leetcode/dayOne/1723. 完成所有工作的最短时间.md",git:{updatedTime:1623368229e3,contributors:[{name:"atrist",email:"atristmu@outlook.com",commits:1}]}}},5582:(e,n,s)=>{s.r(n),s.d(n,{default:()=>r});const a=(0,s(6252).uE)('<h2 id="完成所有工作的最短时间" tabindex="-1"><a class="header-anchor" href="#完成所有工作的最短时间" aria-hidden="true">#</a> 完成所有工作的最短时间</h2><p>给你一个整数数组 <code>jobs</code> ，其中 <code>jobs[i]</code> 是完成第 <code>i</code> 项工作要花费的时间。</p><p>请你将这些工作分配给 <code>k</code> 位工人。所有工作都应该分配给工人，且每项工作只能分配给一位工人。工人的 <strong>工作时间</strong> 是完成分配给他们的所有工作花费时间的总和。请你设计一套最佳的工作分配方案，使工人的 <strong>最大工作时间</strong> 得以 <strong>最小化</strong> 。</p><p>返回分配方案中尽可能 <strong>最小</strong> 的 最大工作时间 。</p><h3 id="示例-1" tabindex="-1"><a class="header-anchor" href="#示例-1" aria-hidden="true">#</a> 示例 1：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：jobs = [3,2,3], k = 3\n输出：3\n解释：给每位工人分配一项工作，最大工作时间是 3 。\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="示例-2" tabindex="-1"><a class="header-anchor" href="#示例-2" aria-hidden="true">#</a> 示例 2：</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>输入：jobs = [1,2,4,7,8], k = 2\n输出：11\n解释：按下述方式分配工作：\n1 号工人：1、2、8（工作时间 = 1 + 2 + 8 = 11）\n2 号工人：4、7（工作时间 = 4 + 7 = 11）\n最大工作时间是 11 。\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div>',8),r={render:function(e,n){return a}}}}]);